	@Test
	void autoIgnoresBudgetAndTimeoutProperties() {
		System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "auto");
		System.setProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, "off");
		System.setProperty(LmdbCascadesOptimizer.BUDGET_PROPERTY, "1");
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "1");

		try (PlannerSession planners = new PlannerSession()) {
			ModeObservation observation = optimize(planners, false);

			assertEquals(OptimizationGoal.SearchMode.AUTO, observation.goal().searchMode());
			assertEquals(4_096, observation.goal().taskBudget(),
					"AUTO uses its fixed deterministic work limit, not cascades.budget");
			assertEquals(Long.MAX_VALUE, observation.goal().deadlineNanos(),
					"AUTO must ignore timeoutMillis even when it is explicitly configured");
		}
	}

	@Test
	void budgetTimeoutAndPolicyParsingRemainStable() {
		assertEquals(500L, LmdbCascadesOptimizer.configuredTimeoutMillis());
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "-1");
		assertEquals(0L, LmdbCascadesOptimizer.configuredTimeoutMillis());
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "0");
		assertEquals(0L, LmdbCascadesOptimizer.configuredTimeoutMillis());
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "37");
		assertEquals(37L, LmdbCascadesOptimizer.configuredTimeoutMillis());
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "invalid");
		assertEquals(500L, LmdbCascadesOptimizer.configuredTimeoutMillis());

		System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "budgeted");
		System.setProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, "off");
		System.setProperty(LmdbCascadesOptimizer.TIMEOUT_MILLIS_PROPERTY, "0");
		try (PlannerSession planners = new PlannerSession()) {
			System.clearProperty(LmdbCascadesOptimizer.BUDGET_PROPERTY);
			assertEquals(4096, optimize(planners, false).goal().taskBudget());
			System.setProperty(LmdbCascadesOptimizer.BUDGET_PROPERTY, "0");
			assertEquals(1, optimize(planners, false).goal().taskBudget());
			System.setProperty(LmdbCascadesOptimizer.BUDGET_PROPERTY, "19");
			assertEquals(19, optimize(planners, false).goal().taskBudget());
			System.setProperty(LmdbCascadesOptimizer.BUDGET_PROPERTY, "invalid");
			assertEquals(4096, optimize(planners, false).goal().taskBudget());

			System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "shadow");
			assertPolicy(planners, null, "fallback");
			assertPolicy(planners, "off", "off");
			assertPolicy(planners, "false", "off");
			assertPolicy(planners, "none", "off");
			assertPolicy(planners, "shadow", "shadow");
			for (String alias : List.of("fallback", "auto", "compare", "true", "bound", "bounded", "shortcut",
					"short-circuit", "standard", "unknown", "")) {
				assertPolicy(planners, alias, "fallback");
			}
		}

		System.clearProperty(LmdbCascadesOptimizer.MODE_PROPERTY);
		System.clearProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY);
		assertTrue(LmdbCascadesOptimizer.standardPlanBaselineCaptureEnabled());
		System.setProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, "shadow");
		assertFalse(LmdbCascadesOptimizer.standardPlanBaselineCaptureEnabled());
		System.setProperty(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, "fallback");
		System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "shadow");
		assertFalse(LmdbCascadesOptimizer.standardPlanBaselineCaptureEnabled());
	}

	@Test
	void connectedTraceAndOpaqueDefaultsRemainStable() {
		assertTrue(LmdbJoinIslandConnectivity.opaqueFactorsEnabled());
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "false");
		assertFalse(LmdbJoinIslandConnectivity.opaqueFactorsEnabled());

		LmdbCascadesConnectedJoinPlanner.Trace disabled = LmdbCascadesConnectedJoinPlanner.Trace.create();
		assertFalse(disabled.enabled());
		assertEquals("", disabled.snapshot());

		System.setProperty(LmdbCascadesConnectedJoinPlanner.CONNECTED_JOIN_TRACE_PROPERTY, "true");
		System.setProperty(LmdbCascadesConnectedJoinPlanner.CONNECTED_JOIN_TRACE_LIMIT_PROPERTY, "1");
		LmdbCascadesConnectedJoinPlanner.Trace clamped = LmdbCascadesConnectedJoinPlanner.Trace.create();
		assertTrue(clamped.enabled());
		clamped.add("x".repeat(1_021));
		assertEquals(1_021, clamped.snapshot().length());
		clamped.add("x");
		assertTrue(clamped.snapshot().endsWith("<trace-truncated>"), clamped::snapshot);
	}

	private static void assertMode(PlannerSession planners, String configuredMode, boolean serializable,
			String expectedMode, OptimizationGoal.SearchMode expectedSearchMode) {
		setOrClear(LmdbCascadesOptimizer.MODE_PROPERTY, configuredMode);
		ModeObservation observation = optimize(planners, serializable);
		assertEquals(expectedMode, observation.mode());
		assertEquals(expectedSearchMode, observation.goal().searchMode());
		assertEquals(serializable ? PhysicalProperties.ObservationOrder.EXACT_SEQUENCE
				: PhysicalProperties.ObservationOrder.ANY,
				observation.goal().requiredProperties().observationOrder());
		if (serializable) {
			assertEquals("false", observation.applied());
		}
	}

	private static void assertDisabledMode(PlannerSession planners, String configuredMode) {
		setOrClear(LmdbCascadesOptimizer.MODE_PROPERTY, configuredMode);
		ModeObservation observation = optimize(planners, false);
		assertNull(observation.mode());
		assertNull(observation.goal());
	}

	private static void assertPolicy(PlannerSession planners, String configuredPolicy, String expectedPolicy) {
		setOrClear(LmdbCascadesOptimizer.STANDARD_PLAN_POLICY_PROPERTY, configuredPolicy);
		assertEquals(expectedPolicy, optimize(planners, false).standardPlanPolicy());
	}

	private static ModeObservation optimize(PlannerSession planners, boolean serializable) {
		int goalIndex = planners.goalCount();
		QueryRoot root = new QueryRoot(new StatementPattern(new Var("subject"), new Var("predicate"),
				new Var("object")));
		new LmdbCascadesOptimizer(new EvaluationStatistics(), false, serializable).optimize(root, null,
				EmptyBindingSet.getInstance());
		return new ModeObservation(root.getStringMetricPlanned("optimizer.cascadesMode"),
				root.getStringMetricPlanned(LmdbCascadesOptimizer.APPLIED_METRIC),
				root.getStringMetricPlanned("optimizer.cascadesStandardPlanPolicy"), planners.goalAt(goalIndex));
	}

	private static CascadesPlan noWinnerPlan(OptimizationGoal goal) {
		return new CascadesPlan(new Memo(CascadesCostModel.from(new EvaluationStatistics())), 0, goal,
				Optional.empty(), OptimizationCompleteness.NO_VIABLE_PHYSICAL_PLAN, List.of(),
				List.of("property-surface-characterization"));
	}

	private static void setOrClear(String property, String value) {
		if (value == null) {
			System.clearProperty(property);
		} else {
			System.setProperty(property, value);
		}
	}

	private record ModeObservation(String mode, String applied, String standardPlanPolicy, OptimizationGoal goal) {
	}

	private static final class PlannerSession implements AutoCloseable {
		private final List<OptimizationGoal> goals = new ArrayList<>();
		private final MockedConstruction<CascadesPlanner> construction = mockConstruction(CascadesPlanner.class,
				(mock, context) -> when(mock.optimize(any(TupleExpr.class), any(OptimizationGoal.class)))
						.thenAnswer(invocation -> {
							OptimizationGoal goal = invocation.getArgument(1);
							goals.add(goal);
							return noWinnerPlan(goal);
						}));

		private int goalCount() {
			return goals.size();
		}

		private OptimizationGoal goalAt(int index) {
			return index < goals.size() ? goals.get(index) : null;
		}

		@Override
		public void close() {
			construction.close();
		}
	}
